var e=JSON.parse(`[{"id":"L6_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"콜록, 콜록……!","JPN":"ゲホッ、ゲホッ……！","ENG":"*Cough* *Cough*","TWN":"咳咳、咳咳……！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"으윽! 갑자기 무슨……. 어디서 가스라도 터진 건가?","JPN":"ううっ！　いきなり……どこかでガスが爆発したのか？","ENG":"Ngh! What was that...? Did a gas explosion happen somewhere?","TWN":"呃！突然發生什麼事了……哪裡瓦斯爆炸了嗎？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"운이 좋았어. 팔도 다리도 멀쩡해.","JPN":"運がよかった……腕も足もなんともない。","ENG":"I got lucky. All my limbs are fine.","TWN":"運氣還不錯，手臂和腿都還完好。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"잠깐, 아이는!?","JPN":"しまった、子どもは！？","ENG":"Wait, what about the kid?!","TWN":"等等，孩子呢？！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"으으…….","JPN":"うう……","ENG":"Ngh...","TWN":"咳咳……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"다행이야. 미약하지만, 아직 숨을 쉬고 있어.","JPN":"浅いけどまだ呼吸している。よかった。","ENG":"Thank goodness. It's weak, but she's still breathing.","TWN":"太好了。雖然很微弱，但好歹還有呼吸。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"하지만 공기 호흡기가 망가졌어.","JPN":"でも呼吸器が壊れてしまったな。","ENG":"But my oxygen tank is broken.","TWN":"但我的空氣呼吸器壞掉了。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이대로는 얼마 못 버틸 거야. 빨리 여기서 나가야…… ","JPN":"このままだと長く持たない。早くここから出ないと…… ","ENG":"We won't be able to last long. We need to get out of here...","TWN":"這樣下堅持不了太久。我得趕緊離開這裡……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"어?","JPN":"え？","ENG":"Huh?","TWN":"呃？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"끄으윽……!","JPN":"ぐうぅ……！","ENG":"Errrgh...!","TWN":"咳呃……！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"대, 대장님!? 정신 차리십시오!!","JPN":"た、隊長！？　しっかりしてください！！","ENG":"C-Captain?! You okay?!","TWN":"隊、隊長？！你醒醒！！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L24_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"꼴통……?","JPN":"お前か……？","ENG":"Knucklehead...?","TWN":"小丫頭……？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"아이는……? 구조자는 어떻게 됐어……?","JPN":"子どもは……？　救助者は、どうなった……？","ENG":"The child.. What happened to her...?","TWN":"孩子呢……？求救者怎麼樣了……？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"살아있습니다!","JPN":"生きています！","ENG":"She's alive!","TWN":"她還活著！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}}},{"id":"L27_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그, 그보다……! 무너진 건물 잔해가 대장님의 하반신을 짓누르고 있습니다!","JPN":"そ、それより……！　隊長の下半身が瓦礫に埋もれています！","ENG":"B-besides that...! The rubble from the collapsed building crushed your lower body!","TWN":"不、不過……！隊長，你下半身被壓在了殘骸下面！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"}}}},{"id":"L28_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"피가, 피가 많이 난다고요!!","JPN":"血が……出血がひどい……！！","ENG":"Th-there's a lot of blood!!","TWN":"血，你流了好多血！！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"그러냐……? 이상하다. 왜 하나도 안 아프지……?","JPN":"そうか……？　おかしいな、全然痛くねえ……","ENG":"Is that so...? That's odd. Why don't I feel any pain...?","TWN":"是嗎……？奇怪，我為什麼一點都不覺得痛……？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"지금 꺼내드릴 테니까, 더는 아무 말도 하지 마십시오!","JPN":"今助けますから、何も喋らないで！！","ENG":"I'll get you out now, so stop talking!","TWN":"我現在就救你出來，你別再說話了！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L33_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"으으윽!! 제발!! 제발 움직여……!!","JPN":"うううっ！！　動け！！　お願いだから、動いてくれ……！！","ENG":"Ngh!! C'mon!! MOOOVE...!!","TWN":"呃啊！！加把勁！！快抬起來了……！！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"끄으윽!","JPN":"ぐうぅ……！","ENG":"ERRRGH!","TWN":"咳呃!"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE_06"},{"id":"L36_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"조금만…… 조금만 더 버티는 겁니다……!!","JPN":"もう少し……もう少し耐えてください……！！","ENG":"Just hang in there... a little longer...!!","TWN":"再……再堅持一下……！！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"으윽!! 제가…… 제가 반드시……!!","JPN":"ううっ！！　アタシが……アタシが必ず……！！","ENG":"Argh!! I'll... get you...!","TWN":"呃啊！！我……我一定……！！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"으으!! 으아아아아아아아아아아아……!!","JPN":"うう……うああああああああ……！！","ENG":"Agh!! AAAAARGH...!!","TWN":"呃呃！！啊啊啊……！！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"하아, 하아, 하아……!!","JPN":"はあ、はあ、はあ……！！","ENG":"*Huff* *Huff* *Huff*","TWN":"哈啊，哈啊，哈啊……！！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"됐다! 잔해를 치웠어!","JPN":"よし、やった！　瓦礫をどかせた！","ENG":"I did it! I cleared the rubble!","TWN":"好了！清理完了！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"대장님! 부축해드리겠습니다! 어서!","JPN":"隊長！　肩を貸します！　掴まってください！","ENG":"Captain! I'll support you! So!","TWN":"隊長！我扶你起來！快點！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"저, 저런 게…… 나를 깔아뭉개고 있었다고……?","JPN":"あ、あんなもんに……俺は押しつぶされていたのか……？","ENG":"Th-that was... on top of me...?","TWN":"我被那、那麼大的石頭……壓著了……？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAP","face":"UNIT_IDLE"},"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L44_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"너, 저걸 어떻게 들어 올린 거냐?","JPN":"お前、どうやってあれを退けたんだ？","ENG":"H-how did you manage to lift that?","TWN":"你是怎麼把它舉起來的？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAP","face":"UNIT_IDLE"},"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"저도 모릅니다!!","JPN":"アタシにもわかりません！！","ENG":"I don’t know, sir!!","TWN":"我也不知道！！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그보다 여기서 빨리 나가야 합니다!! 추가 붕괴가 있을지도 모른다고요!!","JPN":"それより、早くここから出ないと！！　また崩壊するかもしれません！！","ENG":"That's not the point! We gotta get out of here!! The building might collapse even more!!","TWN":"比起這個，我們得趕緊離開這裡！說不定還會再次坍塌的！！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"야, 꼴통…… 나 큰일났다.","JPN":"おい……大変だ。","ENG":"Hey, knucklehead... I'm in trouble.","TWN":"喂，丫頭……我們麻煩大了。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"다리를 못 움직이겠어. 하반신에 감각이 전혀 없어.","JPN":"足が動かない。下半身に感覚がまったくないんだ。","ENG":"I can't move my legs. I can't feel anything below the waist.","TWN":"我的腿動不了了。下半身……沒有什麼感覺了。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAP","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"괜찮습니다! 조금만 참으십시오!","JPN":"大丈夫です！　少しだけ我慢してください！","ENG":"You're gonna be fine! Just hold on a little longer!","TWN":"會沒事的！請忍耐一下！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"나가서 치료받으면 쌩쌩해질 겁니다!","JPN":"外に出て、治療したら治りますよ！","ENG":"You'll be good as new after getting treated!","TWN":"等出去接受了治療，就會好起來的！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"아이는? 구조자는 아직 괜찮냐?","JPN":"子どもは？　救助者は、まだ無事か？","ENG":"What about the kid? Is she all right?","TWN":"孩子呢？求救者還好嗎？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"아직 숨은 쉬고 있지만, 제 공기 호흡기가 망가졌습니다.","JPN":"まだ息はしているけど、アタシの空気呼吸器が壊れてしまいました。","ENG":"She's still breathing, but my oxygen tank is broken.","TWN":"孩子還有呼吸，但我的空氣呼吸器壞掉了。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그러니까 서둘러야 합니다!","JPN":"だから急がないと！","ENG":"So we have to hurry!","TWN":"所以我們必須趕快……！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAP","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"지금 뭐하시는 겁니까! 왜 면체를……?","JPN":"何をしているんですか？　なぜ空気呼吸器を……？","ENG":"What are you doing? Why are you taking off your mask...?","TWN":"你在幹什麼？為什麼要把面罩……？"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L18_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"불길이 점점 거세지고 있어. 난 움직일 수 없고.","JPN":"炎がどんどん強くなっている。そして俺は動けない。","ENG":"The fire's getting bigger, and I can't move.","TWN":"火勢越來越大了。我已經動不了了。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"내 공기통을 나눠 써라. 구조자의 생존이 최우선이야.","JPN":"俺の酸素ボンベを使え。救助者の生存が最優先だ。","ENG":"Use my oxygen tank. Saving the kid is our number one priority.","TWN":"你把我的氧氣瓶拿走吧。保障求救者的生命安全是最重要的。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"우리 셋이 함께 밖에 나가기에는……아마 산소가 부족할지도 몰라.","JPN":"3人で一緒に外に出るには……酸素が足りないかもしれない。","ENG":"We might not have enough oxygen... for all three of us to get out of here.","TWN":"這些氧氣可能沒辦法……撐到我們三個人都出去。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"무슨 헛소리입니까! 포기하지 마십시오!","JPN":"何言ってるんですか！　諦めないでください！","ENG":"Don't say that! Don't give up!","TWN":"你在瞎說些什麼！不要放棄啊！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L22_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"소방관은 구조자의 목숨도, 스스로의 목숨도 놓치지 말아야 한다고 하시지 않았습니까!","JPN":"消防士は救助者の命も、自分の命も守ってみせるものだと……","ENG":"You said that a firefighter shouldn't give up on the rescuee's and their own life!","TWN":"不是你說的嗎！不管是求救者還是自己的生命，消防員都不應該輕易放棄！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"자기 목숨까지 버릴 일은 아니라면서요!!","JPN":"自分の命も守れと言ったじゃないですか！","ENG":"You said it wasn't worth losing your life over!!","TWN":"不是說過不可以放棄自己的生命嗎！！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"제기랄!! 그래도 애는 살려야 할 거 아니야!!","JPN":"ちくしょう！！　でも子どもは助けないといけないだろ！！","ENG":"Dammit!! But you have to save that kid!!","TWN":"該死的！！別忘了你還得救那個孩子啊！！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_HIT_SMASH_SMALL_02"},{"id":"L26_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"어쩔 수 없잖아!! 그 애가 무사하기만을 기다리는 가족들이 있을 텐데!!","JPN":"仕方ねえんだ！！　その子の無事を祈ってる家族がいるはずだ！！","ENG":"There's nothing else we can do!! That kid's parents are out there waiting for her to return to their arms!!","TWN":"沒別的辦法了！！那個孩子的家人肯定在等著她平安回去！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그렇지만 대장님에게도 가족이……!","JPN":"ですが、隊長にも家族が……！","ENG":"But you also have a family, sir...!","TWN":"但是隊長你也有家人……！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"내가 선택한 거야……! 이제 내 차례가 왔을 뿐이라고……!","JPN":"俺が選んだんだ……！　俺の番になった、それだけだ……！","ENG":"It's my choice...! My time has come...!","TWN":"這是我的選擇……！不過是該輪到我了……！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAP","text":{"KOREA":"후회 같은 건 없어!! 그러니까 빨리 가!!","JPN":"後悔なんかしない！！　だから早く行け！！","ENG":"I have no regrets!! So go!!","TWN":"我沒有什麼好遺憾的！！所以，快點走！！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"……젠장! 알겠습니다!","JPN":"……くそ！　わかりました。","ENG":"...Gah! Roger that!","TWN":"……該死的！我知道了！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"후으으…….","JPN":"ふうぅ……","ENG":"Uhhhh...","TWN":"呼……呼……"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그래도 전 포기 안 했습니다, 대장님!","JPN":"でもアタシは諦めてません、隊長！","ENG":"But I haven't given up on you yet, Captain!","TWN":"但我不會放棄的，隊長！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"반드시…… 반드시 돌아오겠습니다.","JPN":"必ず……必ず戻ってきます。","ENG":"I'll... I'll be back for you!","TWN":"我一定……一定會回來救你。"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"그러니까 돌아올 때까지 이 악물고 버티십시오!!","JPN":"だからアタシが来るまで、なんとか耐えてください！！","ENG":"So you'd better stay alive until I get back!!","TWN":"所以，一定一定，要堅持住啊！！"},"stage":{"bg":"OFFICE_MESSED","bgm":"CUTSCENE_TRAGEDY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"하아, 하아, 하아……!","JPN":"はあ、はあ、はあ……！","ENG":"*Huff* *Huff* *Huff*","TWN":"哈啊，哈啊，哈啊……！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L46_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"다행히 중앙 계단은 무너지지 않았어!","JPN":"よかった、中央階段はまだ壊れてない！","ENG":"Luckily, the main staircase didn't collapse!","TWN":"幸好中間的樓梯沒有坍塌！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"우으…….","JPN":"うう……","ENG":"Ooh...","TWN":"嗚嗚……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAUGHTER_EXTRA_NULL_GIRL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"조금만 참아. 지옥에서 꺼내 줄 테니까!","JPN":"ちょっとだけ我慢して。この地獄から出してやるから！","ENG":"Hang in there, kid. I'll get you out of this hellhole!","TWN":"再忍一忍。我會帶你脫離地獄的！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DAUGHTER_EXTRA_NULL_GIRL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"어, 잠깐……?","JPN":"え、あれは……？","ENG":"Huh? Hold on...","TWN":"呃，等等……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"저기 쓰러져 있는 거, 사람 아니야……!?","JPN":"あそこに倒れてるのは……人……！？","ENG":"Is that... a person lying down there...?!","TWN":"有人……躺著那裡嗎……？！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이 방화복!? 먼저 투입된 구조팀이잖아!","JPN":"この防火服……先に投入された救助チームだ！","ENG":"A fire suit?! It's the rescue team that went in before us!","TWN":"這個消防服？！這是最先派來的救援隊！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L10_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"어째서 여기에……?","JPN":"どうしてここに……？","ENG":"But why are they here...?","TWN":"可為什麼在這裡……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"복부에 과다 출혈 확인……! 화재로 죽은 게 아니야……!","JPN":"腹部に出血過多……！　これは火災で死んだんじゃない……！","ENG":"I see excessive bleeding from the abdomen...! They didn't die from the fire...!","TWN":"腹部大量出血……！他不是因為火災喪命的……！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"마치 짐승이 물어 뜯은 것 같은…… ","JPN":"まるで、獣に食いちぎられたような…… ","ENG":"It's as if they were torn apart by a beast...","TWN":"好像被什麼動物咬的一樣……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"읏!?","JPN":"うっ！？","ENG":"Ngh?!","TWN":"呃？！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"뭐야, 이 괴물들은!?","JPN":"なんだ、この化け物たちは！？","ENG":"What are those monsters?!","TWN":"這都是些什麼怪物？！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_HOWLING_02"},{"id":"L17_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이 녀석들이 구조팀을 죽인 건가?","JPN":"こいつらが救助チームを殺したのか？","ENG":"Did those things kill the rescue team?","TWN":"是這些東西殺死了救援隊的人嗎？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"들개? 아니, 뭔가 달라!","JPN":"野犬？　いや、何か違う！","ENG":"Wild dogs? No, something's different!","TWN":"野狗？不，不太像！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"애초에 불이 난 곳에 들개가 나타날 리 없잖아!","JPN":"そもそも火災現場に野犬なんて現れるわけがない！","ENG":"There's no way a wild dog would stay in a fire in the first place!","TWN":"野狗不可能出現在火災現場！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BREATH_MASK"},{"id":"L23_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"젠장, 호흡이 약해지고 있어.","JPN":"くそ、呼吸がさっきより浅くなっている。","ENG":"Crap, her breathing is getting weaker.","TWN":"該死，她的呼吸越來越弱了。"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"고민할 시간이 없어. 1분 1초라도 빨리 여기서 나가야 돼!","JPN":"悩んでる場合じゃない。1分1秒でも早くここから出ないと！","ENG":"I don't have time to worry. I need to get out of here ASAP!","TWN":"沒有時間想這些了。我必須儘快離開這裡！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"크윽, 그러니까……!","JPN":"くっ、だから……！","ENG":"Kgh! So...!","TWN":"呃，所以……！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"뭐지!? 갑자기 괴물이……!?","JPN":"なんだ！？　急に化け物が……！？","ENG":"Huh?! That monster suddenly...?!","TWN":"什麼啊？！這些怪物突然就死了……？！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"얼음 조각이…… 괴물을 꿰뚫은 채로 순식간에 얼어붙었어……?","JPN":"氷の破片が化け物を貫いて……一瞬で凍りついた……？","ENG":"An icicle... suddenly pierced that monster and it instantly froze...?","TWN":"冰塊……突然穿過這些怪物，把它們凍住了……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_HOWLING_03"},{"id":"L35_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"내가 지금 뭔가 헛것을 보고 있는 건가……?","JPN":"アタシは今幻覚を見てるのか……？","ENG":"Or am I seeing things...?","TWN":"我是不是看見幻覺了……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"대체 어디서 날아오는 거지……?","JPN":"いったいどこから飛んできた……？","ENG":"Where did that come from...?","TWN":"到底是從哪裡來的……？"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"정문으로 통하는 복도가 꽁꽁 얼어붙어서 불이 꺼졌어!","JPN":"正門に繋がる廊下が凍りついて、火が消えてる！","ENG":"The fire in the corridor leading to the main entrance has been extinguished and has frozen over!","TWN":"走廊裡的火也凍住了，這條路正好通向正門！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"젠장! 뭐가 뭔지 잘 모르겠지만, 지금이 기회야!","JPN":"くそ、何がなんだかわからないけど今がチャンスだ！","ENG":"Gah! I don't know what's going on, but now's my chance!","TWN":"雖然不確定那是什麼，但現在是好機會！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"일단, 구조자부터 살리는 거야!","JPN":"とりあえず救助者を助ける！","ENG":"But first, I need to get this kid out of here!","TWN":"首先，救人要緊！"},"stage":{"bg":"COUNTERSIDE_BUILDING","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"……앞서 보도해 드렸던 화재는 여전히 진압되지 않고 있는데요.","JPN":"……先程お伝えした火災に関しまして、依然として鎮圧されていないとのことです。","ENG":"...The fire we reported earlier has yet to be extinguished.","TWN":"……先前報導的火災目前仍在持續中。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L46_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"소방 당국은 한 차례 초도 진압 후, 구조대를 투입하여 구조 활동을 수행하였지만.","JPN":"消防当局は初動活動を行った後、救助隊を投入して救助活動を遂行したものの……","ENG":"After the fire department's initial suppression, the rescue team was deployed.","TWN":"經過初步撲滅後，消防部門迅速調派了專業的救援隊伍進行緊急救援工作。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"갑작스러운 폭발로 건물이 붕괴하여서 투입된 구조대원들이 매몰되었다고…….","JPN":"突然の爆発により建物が崩壊し、救助隊員らが埋もれたと……","ENG":"However, a sudden explosion caused the building to collapse, burying the dispatched rescue team in rubble...","TWN":"不幸的是，大樓因突發爆炸而倒塌，部分救援隊員被掩埋……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"아! 말씀드린 순간, 속보입니다!","JPN":"あっ、今速報が入りました！","ENG":"Oh! This just in. Breaking news!","TWN":"啊！記者現在收到最新消息！"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"화재 현장에 투입되었던 구조 대원이 무사히 빠져나오고 있습니다!","JPN":"火災現場に入った救助隊員が無事外に出て来ました！","ENG":"One of the dispatched rescue team members got out of the fire safely!","TWN":"其中一位趕赴火災現場的救援隊員安全逃生了！"},"stage":{"bg":"YAKSHA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"아이……! 대원이 아이를 안고 있습니다!","JPN":"子ども……！　隊員が子どもを抱きかかえています！","ENG":"A child...! She's holding a child in her arms!","TWN":"孩子……！消防隊員抱著孩子！"},"stage":{"bg":"YAKSHA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"이쪽이야! 빨리 찍어! 이런 특종을 놓칠 수는 없다고!","JPN":"こっちだ！　早く撮るんだ！　こんなスクープを逃すわけにはいかない！","ENG":"Over here! Get that photo! We can't miss a scoop like this!","TWN":"跟我來！快點拍！我們不能錯過這個獨家新聞！"},"stage":{"bg":"YAKSHA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L7_1","type":"dialog","speaker":null,"text":{"KOREA":"말도 안 돼. 저런 화재 속에서 살아나왔다고?","JPN":"なんてことだ……あんな火災現場から生きて出てこれたとは……！","ENG":"No way. She made it out alive in that fire?","TWN":"不可思議。她是怎麼從這樣的大火中倖存下來的？"},"stage":{"bg":"YAKSHA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":null,"text":{"KOREA":"어라? 저 구조 대원, 뭔가 좀 이상하지 않아?","JPN":"あれ？　あの救助隊員、何かおかしくないか？","ENG":"Huh? But that firefighter, doesn't she look a little weird?","TWN":"嗯？你不覺得那個隊員看起來有些奇怪嗎？"},"stage":{"bg":"YAKSHA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L9_1","type":"dialog","speaker":null,"text":{"KOREA":"머리에 무슨 동물 귀 같은 게…….","JPN":"頭に動物の耳みたいなものが……","ENG":"She has animal ears on her head...","TWN":"她的頭上長著某種動物的耳朵……"},"stage":{"bg":"YAKSHA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>그 때, 나는 아무것도 알지 못했다.</color>","JPN":"<color=#ffd34c>その時、アタシは何も知る由も無かった。</color>","ENG":"<color=#ffd34c>At that time, I knew nothing.</color>","TWN":"<color=#ffd34c>那時，我還沒有意識到。</color>"},"stage":{"bg":"YAKSHA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"구조자 1명…… 구조 완료하였습니다.","JPN":"救助者1名……救助完了しました。","ENG":"One child... rescue complete.","TWN":"成功救出一名倖存者……"},"stage":{"bg":"YAKSHA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"숨을 쉬지 않습니다! 빨리, 빨리……! 조치가 필요합니다!","JPN":"息をしていません！　早く、早く……！　応急措置をお願いします！","ENG":"She's not breathing! Please, hurry...! Help her!","TWN":"她沒呼吸了！快、快點……！救救她……！救救她！"},"stage":{"bg":"YAKSHA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L15_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>공기 호흡기가 새고 있어서, 충분한 산소가 전달되지 않았다는 것도.</color>\\n<color=#ff3636>공기 호흡기가 새고 있는데, 산소 부족을 느끼지 못했다는 것도.</color>","JPN":"<color=#ffd34c>空気呼吸器が壊れていて、酸素が漏れていたということも。</color>\\n<color=#ff3636>酸素が漏れているのに、自分は酸素不足を感じられなかったということも。</color>","ENG":"<color=#ffd34c>Not about the oxygen tank leaking and the kid not receiving enough oxygen as a result of it.</color>\\n<color=#ff3636>Or even the fact I didn't notice the lack of oxygen while it was leaking.</color>","TWN":"<color=#ffd34c>為什麼那個小女孩會因為空氣呼吸器漏氣而窒息，</color>\\n<color=#ff3636>而同樣用著呼吸器的我卻沒有半點感覺。</color>"},"stage":{"bg":"YAKSHA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"저는 다시 들어가야 합니다!","JPN":"アタシは戻らないといけません！","ENG":"I need to get back in there!","TWN":"我還得返回火災現場！"},"stage":{"bg":"YAKSHA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L17_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"저 불 속에는…… 아직 우리 대장님이 계신다고요!","JPN":"あの中に……隊長がいるんです！","ENG":"My captain... is still in that fire!","TWN":"我們的隊長……還被困在火裡！"},"stage":{"bg":"YAKSHA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>대장님이 잔해에 깔려서 죽을 수밖에 없었던 이유도.</color>\\n<color=#ff3636>내가 잔해에 깔리고도 멀쩡하게 살아남을 수 있었던 이유도.</color>","JPN":"<color=#ffd34c>隊長が瓦礫に埋もれて死ぬしかなかった理由も。</color>\\n<color=#ff3636>アタシも瓦礫に埋もれたのに無事生き残ることができた理由も。</color>","ENG":"<color=#ffd34c>The reason why Captain had to die being buried in rubble.</color>\\n<color=#ff3636>Or how I was able to make it out of there without even a scratch.</color>","TWN":"<color=#ffd34c>為什麼隊長被壓在殘骸底下身受重傷，</color> \\n<color=#ff3636>而我被壓在殘骸下面，卻幾乎毫髮無傷。</color>"},"stage":{"bg":"YAKSHA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"진정해! 브레이드우드 소방수!","JPN":"落ち着け、ブレイドウッド消防士！","ENG":"Calm down, Officer Braidwood!","TWN":"冷靜點！布雷德伍德消防員！"},"stage":{"bg":"YAKSHA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"진정하고 대답해! 현장에 들어간 다른 팀원들은 어떻게 됐나!?","JPN":"落ち着いて答えるんだ！　現場に入った他の隊員はどうなった！？","ENG":"Cool it and answer me! What happened to the rest of your team who went in?!","TWN":"你冷靜點回答我！進入現場的其他隊員怎麼樣了？！"},"stage":{"bg":"YAKSHA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>현장에서 갑작스레 원인불명의 폭발이 발생했던 것도.</color>\\n<color=#ff3636>현장에서 갑작스레 정체불명의 괴물이 나타났던 것도.</color>","JPN":"<color=#ffd34c>現場で突然原因不明の爆発が発生したのも。</color>\\n<color=#ff3636>現場で突然謎の化け物が現れたのも。</color>","ENG":"<color=#ffd34c>Not the sudden unidentified explosion at the scene,</color>\\n<color=#ff3636>Or why unidentified monsters suddenly appeared there.</color>","TWN":"<color=#ffd34c>還有現場突然發生的不明原因的爆炸，</color>\\n<color=#ff3636>以及突然出現的神秘怪物。</color>"},"stage":{"bg":"YAKSHA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"다시 진입하는 건 무리라고! 2차 붕괴의 위험이 있다!!","JPN":"あの中に戻るのは無理だ！　2次崩壊の恐れがある！","ENG":"You can't go in there again! There's a risk of a secondary collapse!!","TWN":"你不能再進去了！那裡會有二次崩塌的危險！！"},"stage":{"bg":"YAKSHA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"COMMANDER_EXTRA_POLICE_NULL","text":{"KOREA":"다들 브레이드우드 대원을 붙잡아!!","JPN":"皆、ブレイドウッド隊員を捕まえろ！","ENG":"Everyone, stop her!","TWN":"大家快抓住布雷德伍德的隊員！！"},"stage":{"bg":"YAKSHA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"제기랄!! 이거 놔!!","JPN":"くっそ、離せ！！","ENG":"Dammit! Let go of me!!","TWN":"可惡！！放開我！！"},"stage":{"bg":"YAKSHA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"이거 놓으란 말이야!! 개자식들아!!","JPN":"離せって言ってんだろ、くそったれども！！","ENG":"Let me go, you jerks!!","TWN":"我說放開我！！你們這些該死的！！"},"stage":{"bg":"YAKSHA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"다시 들어가야 해!! 아직 저 안에 대장님이 계신다고!!","JPN":"戻らないといけないんだ、あの中に隊長がいるんだよ！！","ENG":"I need to go back in there!! Captain's still in there waiting for me!!","TWN":"我還得回去啊！！隊長還在裡面！！"},"stage":{"bg":"YAKSHA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"젠장, 젠장할!","JPN":"くそ、くそおおお！","ENG":"Dammit! Dammit!","TWN":"該死，該死！"},"stage":{"bg":"YAKSHA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"FIREFIGHTER_YAKSHA_NPC_CAT","text":{"KOREA":"으아아아아아아아아아아아아아아아아!!","JPN":"うああああああああああ！！","ENG":"AAAAAAARGH!!!","TWN":"呃啊啊啊啊啊……！！"},"stage":{"bg":"YAKSHA_02","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L35_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>그 때, 나는 아무것도 알지 못했다.</color>","JPN":"<color=#ffd34c>その時、アタシは何も知る由も無かった。</color>","ENG":"<color=#ffd34c>At that time, I knew nothing.</color>","TWN":"<color=#ffd34c>我那時，還什麼都沒有意識到。</color>"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>아무것도 알지 못한 채, 아무도 구하지 못한 채.</color>","JPN":"<color=#ffd34c>何もわからず、誰も助けられず。</color>","ENG":"<color=#ffd34c>Without knowing anything and unable to save anyone.</color>","TWN":"<color=#ffd34c>懵懵懂懂地，什麼人也沒有救下。</color>"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>그저, 타들어 가는 불꽃 속에서.</color>","JPN":"<color=#ffd34c>ただ、燃え盛る炎の中で。</color>","ENG":"<color=#ffd34c>Alone in the raging fire.</color>","TWN":"<color=#ffd34c>在那場燃燒的火海中。</color>"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"narration","speaker":null,"text":{"KOREA":"<color=#ffd34c>홀로 덩그러니 살아 남아버렸을 뿐이었다.</color>","JPN":"<color=#ffd34c>一人ぽつんと生き残ってしまっただけだった。</color>","ENG":"<color=#ffd34c>Only I survived.</color>","TWN":"<color=#ffd34c>只有我一個人孤零零地活了下來。</color>"},"stage":{"bg":"BLACK","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"……현재, 완전히 전소된 현장에서 잔불 제거와 수색 작업이 진행되고 있는데요.","JPN":"……現在、全焼した現場で残り火の確認と捜索作業が行われています。","ENG":"...The removal and search for residual fires are currently underway at the completely burned site.","TWN":"……目前，現場已被完全燒毀，救援人員正進行餘火清除和搜查工作。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L42_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"소방당국은 화재에서 갑작스레 발생했던 폭발이 플래시 오버 현상이라고 발표했습니다.","JPN":"消防当局は、火災で突然発生した爆発はフラッシュオーバー現象だったと発表しました。","ENG":"Fire officials announced that the sudden explosion during the fire was caused by a flashover.","TWN":"消防部門宣佈，火災過程中發生的突然爆炸，確認為閃燃現象。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"REPORTER_YAKSHA_NPC_NULL","text":{"KOREA":"플래시 오버는 가연성 가스가 쌓여 고열과 만나 폭발이 일어나는 현상으로…….","JPN":"フラッシュオーバーは、蓄積された可燃性ガスが高熱と接触したことで爆発する現象で……","ENG":"A flashover is when accumulated combustible gas comes into contact with high heat, resulting in an explosion...","TWN":"閃燃是由於可燃氣體積聚，在遭遇高溫條件時引發爆炸的現象……"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"FIREFIGHTER_YAKSHA_NPC_CAT","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"RAT_YAKSHA_NPC_NULL","text":{"KOREA":"그래서 결국 어떻게 된 겁니까요, 부전대장님?","JPN":"で、結局どうなったでやんすか？　副戦隊長。","ENG":"Deputy Commander, so what happened in the end?","TWN":"最後到底發生了什麼，副戰隊長？"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L49_1","type":"dialog","speaker":"RABBIT_YAKSHA_NPC_NULL","text":{"KOREA":"우리 임무는 완수했어. 나머지 은폐 작업은 관리국이 주도하겠지.","JPN":"私たちの任務は完遂した。残りの隠ぺい工作は管理局がやってくれるでしょう。","ENG":"We completed our mission. The rest of the cover-up will be done by the Administration.","TWN":"我們的任務完成了。管理局會負責其餘的掩蓋工作。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"RAT_YAKSHA_NPC_NULL","text":{"KOREA":"흥! 임무 같은 건 아무래도 좋습니다요!","JPN":"ふん！　任務なんかどうでもいいでやんす！","ENG":"Hmph! I don't care about the mission!","TWN":"哼！任務怎麼樣都好！"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NPC_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L1_1","type":"dialog","speaker":"RAT_YAKSHA_NPC_NULL","text":{"KOREA":"제가 궁금한 건, 이번에 각성한 그 <color=#ffd34c>신참</color> 녀석입니다요.","JPN":"あたいは今回覚醒したあの<color=#ffd34c>新入り</color>のほうが気になるでやんす。","ENG":"What I do care about is the newly awakened <color=#ffd34c>rookie</color>.","TWN":"我好奇的是，這次覺醒的那個<color=#ffd34c>新人</color>！"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"RAT_YAKSHA_NPC_NULL","text":{"KOREA":"대체 무슨 대단한 일을 했길래, 하이브 컨트롤이 그 녀석을 선택한 겁니까요?","JPN":"ハイブコントロールに選ばれるなんて、いったいどんなすごいことをやったでやんすか？","ENG":"What's so special about her that Hive Control chose her?","TWN":"她到底做了什麼，讓巢穴控制系統選擇了她？"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"RAT_YAKSHA_NPC_NULL","text":{"KOREA":"쳇, 아주 낯짝이 궁금합니다요.","JPN":"どんなツラか見てみたいでやんす。","ENG":"Tch, I'm so curious to see that mug of hers.","TWN":"嘖，真想看看她長什麼樣子。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"RABBIT_YAKSHA_NPC_NULL","text":{"KOREA":"글쎄? 첫인상을 묻는 거라면…….","JPN":"さあ？　第一印象は……","ENG":"Well, if you're asking about her first impression...","TWN":"是嗎？要說第一印象……"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"RABBIT_YAKSHA_NPC_NULL","text":{"KOREA":"으음, 가엾은 길고양이 같은 애라고 해야할까?","JPN":"うーん、可哀想な野良猫っぽい子、といったところかな？","ENG":"Hmm, should I say she's like a poor stray cat?","TWN":"嗯，就像是一隻可憐的流浪貓？"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RAT_YAKSHA_NPC_NULL","text":{"KOREA":"고양이말입니까요? 고양이는 싫습니다요!","JPN":"猫でやんすか？　猫は嫌いでやんす！","ENG":"A cat? But I hate cats!","TWN":"你說貓？我不喜歡貓！"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RAT_YAKSHA_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RABBIT_YAKSHA_NPC_NULL","text":{"KOREA":"……후후.","JPN":"……ふふ。","ENG":"...Fu fuu.","TWN":"……呵呵。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RAT_YAKSHA_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"RABBIT_YAKSHA_NPC_NULL","text":{"KOREA":"그래도 곧 같은 식구가 될 텐데 너무 미워하진 마.","JPN":"でもこれから家族になるわけだし、あまり嫌わないでね。","ENG":"But she's soon going to be part of our family, so don't hate her too much.","TWN":"我們很快就會成為一家人了，所以不要太討厭她喔。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"RAT_YAKSHA_NPC_NULL","text":{"KOREA":"흥! 아무튼 전 반대인 겁니다요!","JPN":"ふん！　とにかくあたいは反対でやんす！","ENG":"Hmph! Anyway, I'm against it!","TWN":"哼！總之，我反對！"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"THMEA_SAD_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RAT_YAKSHA_NPC_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"RABBIT_YAKSHA_NPC_NULL","text":{"KOREA":"고양이라…….","JPN":"猫、か……","ENG":"A cat...","TWN":"貓啊……"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L15_1","type":"dialog","speaker":"RABBIT_YAKSHA_NPC_NULL","text":{"KOREA":"어쩌면 우리 전대가 옛날처럼 다시 시끌벅적해질지도 모르겠네요.","JPN":"もしかしたらうちの戦隊、昔みたいにまた賑やかになるかもしれませんね。","ENG":"Maybe our division will be bustling again like it used to be.","TWN":"也許，我們戰隊又會像以前一樣熱鬧了。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RABBIT_YAKSHA_NPC_NULL","text":{"KOREA":"……전대장님.","JPN":"……戦隊長。","ENG":"...Commander.","TWN":"……戰隊長。"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RABBIT_YAKSHA_NPC_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};